m[x++]='13:$<b>Befähigung</b>';
m[x++]='14:Sachkundige und Aufsichtsführende benennen (z. B. bei Abbruch-/Demontagearbeiten, Arbeiten in <a href="'+xpath+'ga_bau/f_ko/ko16023.htm">engen Räumen</a>, Umgang mit <a href="'+xpath+'ga_bau/f_g/g6015.htm">Asbest</a>, <a href="'+xpath+'ga_bau/f_g/g60531.htm">PCB</a>)';
