datum[z]='150801';
titel[z]='Arbeiten in Bereichen mit Infektionsgefahr';
gefahr[z]='Gefährdungsfaktoren: Biologische Arbeitsstoffe';
fragen[z]='Welche Maßnahmen werden getroffen gegen Infektionsgefahren durch Keime und andere biologische Stoffe (zum Beispiel bei Arbeiten an Klimaanlagen, an <a href="'+xpath+'tr/trba220/3.htm">Abwasseranlagen</a>, bei der <a href="'+xpath+'dguv/201_005/titel.htm">Bodensanierung</a>, Krankenhausreinigung)?';
m[x++]='00:Durch einen Fachkundigen werden die Höhe der Belastung der Arbeiten mit Infektionsgefahr, die Übertragungswege und die Einstufung in Risikogruppen vorgenommen.';
m[x++]='01:Die allgemeinen Hygienemaßnahmen sind umgesetzt – zum Beispiel <b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_biolArbeitsstofl_Allg\')">Schutzmaßnahmen beim Umgang mit biologischen Stoffen - Mindeststandards</a> zur Überprüfung verwenden';
m[x++]='02:Ein Hygieneplan des Auftraggebers liegt vor und wird umgesetzt';
m[x++]='03:$<b>Maßmahmen entsprechend Einstufung der Arbeiten in die Risikogruppen 2 oder 3</b>';
m[x++]='04:Arbeitsverfahren mit geringerer Staub- oder Aerosolbildung auswählen (zum Beispiel Staubsauber mit Schwebstofffiltern)';
m[x++]='05:Arbeitsmittel auswählen, die die Gefahr durch Stich- und Schnittverletzungen verhindern oder minimieren ';
m[x++]='06:Be- und Entlüftung (zum Beispiel technische Lüftungsmaßnahmen); abgesaugte Luft nicht ungereinigt ableiten';
m[x++]='07:Verfahren zur Desinfektion, Inaktivierung oder Dekontamination bei der Entsorgung und nach Beendigung der Arbeiten festlegen – zum Beispiel Transport des infektiösen Materials erfolgt in sicher verschlossenen und gekennzeichneten Transportbehältnissen ( zum Beispiel Kunststoffsäcke, Spezialbehälter)';
m[x++]='08:Anzahl der Beschäftigten, die der Infektionsgefahr ausgesetzt sind, so gering wie möglich halten.';
m[x++]='09:Persönliche Schutzausrüstung zur Verfügung stellen (Atemschutz, Augenschutz, Schutzkleidung, Schutzhandschuhe, Schutzschuhe)';
m[x++]='10:Bei <a href="'+xpath+'tr/trgs401/2.htm">Feuchtarbeiten</a> zusätzlich Baumwollunterziehhandschuhe unter dem flüssigkeitsdichten Schutzhandschuh tragen ';
m[x++]='11:Persönliche Schutzausrüstung reinigen, instand halten und sachgerecht entsorgen (zum Beispiel abwaschbare Sicherheitsstiefel, abwaschbare Schutzhandschuhe)';
m[x++]='12:Bei Tätigkeiten mit biologischen Arbeitsstoffen oder Bereichen mit Infektionsgefahr ist eine arbeitsmedizinische Vorsorge erregerspezifisch zu veranlassen oder anzubieten. <a href="'+xpath+'gv/arbmedvv/anh.htm">Erregerermittlung/Expositionsart</a> in Abstimmung mit dem Betriebsarzt oder Betriebsärztin, ggf. nach Angaben des Auftraggebers.';
m[x++]='13:Hautschutz gemäß <a href="'+xpath+'ga_bau/inhalt1/0hsp0.htm">Hautschutzplan</a> (Betriebsarzt oder Betriebsärztin/ASD der BG BAU fragen)';
m[x++]='14:Nur anhand der <a href="'+xpath+'ga_bau/f_g/g60281.htm">Betriebsanweisung</a> <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen. <a href="'+xpath+'ga/db.htm?data6"><img src="../grafik/n.gif"></a>';
m[x++]='15:Bei <a href="'+xpath+'dguv/101_017/anh4.htm">Verletzungen durch scharfe und/oder spitze Gegenstände</a> (zum Beispiel Nadelstichverletzungen, Schnittverletzungen) umgehend D-Arzt aufsuchen';
