m[x++]='06:<a href="'+xpath+'ga_bau/f_g/g6061.htm">Absaugeinrichtungen</a>; abgesaugte Luft nicht ungereinigt ableiten';
m[x++]='07:<a href="'+xpath+'ga_bau/f_bue/bue90241.htm">entzündliche/brandfördernde</a> Stoffe außerhalb von Arbeitsbereichen lagern';
m[x++]='08:<a href="'+xpath+'ga_bau/f_bue/bue9056.htm">Zündquellen</a> ausschließen, z.&nbsp;B.: Rauchverbot, Strom ausschalten (Funke im Lichtschalter), Zündflamme in Gas- und Ölbrennern abdrehen, besondere Bedingungen beim Einsatz von <a href="'+xpath+'ga_bau/f_bue/bue90212.htm">Heizgeräten</a> beachten';
