m[x++]='03:Nur anhand der <a href="'+xpath+'ga_bau/f_g/g60281.htm">Betriebsanweisung</a> <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
