titel[z]='Arbeit mit Steinversieglern und Steinklebern';
gefahr[z]='Gefährdungsfaktoren: Gefahrstoffe; Brand und Explosion';
fragen[z]='Welche Maßnahmen werden beim Umgang mit Steinversieglern und Steinklebern getroffen, die zu einer Gefährdung durch Einatmen beziehungsweise Hautkontakt oder zu Brand- und Explosionsgefährdung führen können (zum Beispiel Lösemittel)?';
hinweis_neu[z]='Bei Grenzwertüberschreitung bitte Maßnahmen überprüfen';
m[x++]='18:Ermittlung welche Gefahrstoffe die Steinversiegler und -kleber enthalten - <a href="'+xpath+'ga_bau/f_g/g6009.htm">Sicherheitsdatenblatt</a> nutzen ';
m[x++]='19:Die Höhe der Belastung bei Arbeiten mit Steinversieglern und -klebern wurde ermittelt. Gegebenenfalls werden der <a href="'+xpath+'ga_bau/f_iop/iop036_1.htm">Betriebsarzt oder Betriebsärztin</a> und die <a href="'+xpath+'ga_bau/f_iop/iop039.htm">Fachkraft für Arbeitssicherheit</a> hinzugezogen.';
m[x++]='20:Es wurde überprüft, ob es weniger gefährliche Arbeitsstoffe/-verfahren/-mittel gibt, die im Rahmen des Bauauftrages anwendbar sind.';
m[x++]='16:$<b>Bei geringer Belastung</b>';
m[x++]='00:Nur anhand der <a href="'+xpath+'ga_bau/f_g/g60281.htm">Betriebsanweisung</a> <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen. <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
m[x++]='01:Die allgemeinen Hygienemaßnahmen sind umgesetzt - <b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_gefahrstoffeEinsatz_Allg\')">Schutzmaßnahmen beim Einsatz von Gefahrstoffen - Mindeststandards</a> wird zur Überprüfung verwendet.';
m[x++]='17:$<b>Zusätzlich bei erhöhter Belastung</b>';
m[x++]='02:Bei Tätigkeiten mit Gefahrstoffen (gemäß <a href="'+xpath+'gv/arbmedvv/anh.htm">Anhang ArbmedVV, Teil 1</a>) und Überschreitung des Arbeitsplatzgrenzwertes nur Beschäftigte einsetzen, denen die Teilnahme an der <a href="'+xpath+'gv/arbmedvv/4.htm">arbeitsmedizinischen Pflichtvorsorge</a> bescheinigt wurde. <br />Hinweis_4: Diese Maßnahmenzeile wurde überarbeitet. Bitte überprüfen Sie Ihre Eingaben und Kommentare.';
m[x++]='18:Bei Tätigkeiten, die das Tragen von Atemschutzgeräten der Gruppen 2 und 3 erfordern, nur Beschäftigte einsetzen, denen die Teilnahme an der <a href="'+xpath+'gv/arbmedvv/4.htm">arbeitsmedizinischen Pflichtvorsorge</a> bescheinigt wurde.';
m[x++]='19:Bei sonstigen Tätigkeiten mit Gefahrstoffen (<a href="'+xpath+'gv/arbmedvv/anh.htm">Anhang ArbmedVV, Teil 1</a>) Angebotsvorsorge schriftlich anbieten.';
m[x++]='03:EX-geschützte Werkzeuge und Maschinen';
m[x++]='04:Lüftung/<a href="'+xpath+'ga_bau/f_g/g6061.htm">Absaugeinrichtungen</a>; abgesaugte Luft nicht ungereinigt ableiten';
m[x++]='05:<a href="'+xpath+'ga_bau/f_bue/bue90241.htm">entzündliche/brandfördernde</a> Stoffe außerhalb von Arbeitsbereichen lagern; Vorratsmenge auf einen Schichtbedarf beschränken';
m[x++]='06:Zündquellen ausschließen, z.&nbsp;B.:<br> Rauchverbot, Strom ausschalten (Funke im Lichtschalter), Zündflamme in Gas- und Ölbrennern abdrehen, besondere Bedingungen beim Einsatz von <a href="'+xpath+'ga_bau/f_bue/bue90212.htm">Heizgeräten</a> beachten';
m[x++]='07:<a href="'+xpath+'ga_bau/f_bue/bue90242.htm">Feuerlöscher</a>/<a href="'+xpath+'ga_bau/f_bue/bue9032.htm">Löschdecke</a> bereitstellen (gegebenenfalls Brandwache)';
m[x++]='08:<a href="'+xpath+'ga_bau/f_all/all0081.htm">Atem</a>-/<a href="'+xpath+'ga_bau/f_all/all0073.htm">Augen</a>-/<a href="'+xpath+'ga_bau/f_all/all0101.htm">Handschutz</A>';
m[x++]='09:Hautschutz gemäß <a href="'+xpath+'ga_bau/inhalt1/0hsp0.htm">Hautschutzplan</a>';
m[x++]='10:<a href="'+xpath+'ga_bau/f_g/g6065.htm">Augendusche</a> - nach Nutzung der Augendusche Augenarzt aufsuchen';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten (z.B. durch Reaktion mit anderen Gefahrstoffen).';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt (z.B. Gefahrstoffkonzentration messen, mit Grenzwerten abgleichen) – ggf. <a href="'+xpath+'ga_bau/f_iop/iop039.htm">Fachkraft für Arbeitssicherheit</a>/<a href="'+xpath+'ga_bau/f_iop/iop036_1.htm">Betriebsarzt oder Betriebsärztin</a> hinzuziehen.';
