datum[z]='150801';
titel[z]='Spezialtiefbau I - einige Verfahren';
gefahr[z]='Gefährdungsfaktoren: Ungeschützt bewegte Maschinenteile; Unkontrolliert bewegte Teile; Absturz';
fragen[z]='Welche Maßnahmen werden gegen Gefährdungen im Spezialtiefbau, zum Beispiel bei Ankerarbeiten oder beim Herstellen von Ortbetonpfählen und Schlitzwänden getroffen?';
m[x++]='33:$<b>Allgemein<b/>';
m[x++]='34:Überprüfen, welches Arbeitverfahren die geringste Gefährdung aufweist.';
m[x++]='07:$<b>Umgang mit Maschinen</b>';
m[x++]='08:Bedienelemente für gefahrbringende Bewegungen mit Nullstellungszwang (Totmannschaltung)';
m[x++]='09:Gefahrbereiche absperren (z.B. an Bohrschnecken, <a href="'+xpath+'dguv/101_008/4_4.htm">Spunddielen</a>)';
m[x++]='10:Maßnahmen gegen Absturz an Aufstiegen und Arbeitsplätzen > 2,00 m';
m[x++]='11:vorgesehene Werkzeuge verwenden';
m[x++]='12:Anseilschutz';
m[x++]='13:Seitenschutz (Geländer)';
m[x++]='14:Standplatz auf Anlegeleitern max. 7&nbsp;m Höhe für kurzfristige Arbeiten';
m[x++]='15:Steigschutz';
m[x++]='16:Prüfen, ob Untergrund tragfähig und plan ist, sonst Tragfähigkeit und Planum herstellen.';
m[x++]='00:$<b>Ankerarbeiten</b>';
m[x++]='01:automatisch wirkende Sicherheitseinrichtung (z.&nbsp;B. Schaltleiste, Schaltleine) an der Bohrlafette';
m[x++]='02:Gefahrbereiche des Bohrwerkzeugs absperren';
m[x++]='03:vorgesehene Schlagschlüssel oder Zangen verwenden';
m[x++]='04:hydraulische Brecheinrichtung an Ankerbohrgeräten';
m[x++]='05:Nur <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
m[x++]='06:Schutzbrille/Gesichtsschutz und eng anliegende Kleidung tragen';
m[x++]='17:$<b>Ortbetonpfähle, Schlitzwände und Schachtöffnungen</b>';
m[x++]='18:sichere Standplätze zum Aushängen der Anschlaghaken in der Höhe';
m[x++]='19:Nur <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen - zum Ablassen der Bewehrung in tiefe Bohrlöcher oder Schlitze <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
m[x++]='20:Anschlagpunkte an den Bewehrungskörben angeschweißt';
m[x++]='21:Einsatz tragfähiger Hebezeuge mit geeigneten Anschlagmöglichkeiten und ';
m[x++]='22:<span class="einz">•</span> Anschlagmitteln';
m[x++]='23:<span class="einz">•</span> Einweiser';
m[x++]='24:<span class="einz">•</span> augenscheinliche Prüfung der Anschlagmittel auf Mängel';
m[x++]='25:Abstimmung zwischen Maschinenführer/Helfer (z.&nbsp;B. durch Handzeichen, Signale)';
m[x++]='26:Mechanische/hydraulische Verriegelung der Werkzeuge an der Maschine';
m[x++]='27:Abdecken des Bohrlochs';
m[x++]='28:Bohrloch oberhalb des Betons mit Boden verfüllen';
m[x++]='29:Bohrloch umwehren';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten.';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt.';
