ga_dateien['f_spezialtiefbau_zusatz']=z;
datum[z]='150807';
titel[z]='Spezialtiefbau II - weitere Verfahren';
gefahr[z]='Gefährdungsfaktoren: Erfasst und getroffen werden; Unkontrolliert bewegte Teile; Lärm; Ungeschützt bewegte Maschinenteile';
fragen[z]='Welche Maßnahmen müssen ergriffen werden um Gefährdung im <a href="'+xpath+'bausteine/b_184/b_184.htm">Spezialtiefbaus</a> zu verhindern?';
m[x++]='00:$<b>Allgemeine Arbeiten des Spezialtiefbaus</b>';
m[x++]='01:Bestimmung des Aufsichtführenden';
m[x++]='02:Unterweisung Maschinenführer';
m[x++]='03:Unterweisung der Beschäftigte über Maßnahmen, die aus der baustellenbezogenen Gefährdungsbeurteilung resultieren';
m[x++]='04:Erdverlegte Leitungen und Freileitungen sind entfernt oder freigeschaltet';
m[x++]='05:Baugrund frei von Kontamination und Kampfmitteln';
m[x++]='06:Aufstellfläche des Gerätes so, dass räumliche Zusammenarbeit Mensch Maschine möglichst ohne Gefährdung';
m[x++]='07:Einsatzort des Gerätes mit eigenem Fahrwerk erreichbar (wenn nicht ggf. weitere Unterweisung hinsichtlich Transport mittels Mobilkran)';
m[x++]='08:Arbeitsplätze und Verkehrswege sicher begehbar';
m[x++]='09:Beachtung der Standsicherheit des Gerätes';
m[x++]='10:Maschinen allgemein';
m[x++]='11:Geräte nur bestimmungsgemäß betreiben (Betriebsanleitung des Gerätes vor Ort)';
m[x++]='12:Überwachung und Prüfung der Geräte arbeitstäglich durch den Maschinenführer';
m[x++]='13:Prüfungen der Geräte durch eine <a href="'+xpath+'gv/betrsichv/2.htm">zur Prüfung befähigte Person</a> nach Ermittlung der Intervalle durch Arbeitgeber';
m[x++]='14:Ergebnisse der Prüfung dokumentiert und am Einsatzort einsehbar';
m[x++]='15:$<b>Ankerbohrarbeiten</b>';
m[x++]='16:Schutzeinrichtungen immer im betriebsbereiten Zustand halten';
m[x++]='17:Bei Schraubgestänge: Gestängebrecheinrichtung betreiben';
m[x++]='18:Rohre und Gestänge = 25 Kg mit mechanisierten Handhabungssystemen bewegen (Magazin, Manipulator)';
m[x++]='19:Maßnahmen gegen das Herausschnellen von Stahlenden bei Ankern als Ringware';
m[x++]='20:$<b>Bohr- und Rammarbeiten</b>';
m[x++]='21:Hebezeugbetrieb unter Beachtung der Betriebsanleitung';
m[x++]='63:Gefahrenbereich festlegen';
m[x++]='64:Geeignete Anschlagmittel verwenden ( z.B. Knebelkette)';
m[x++]='65:Maßgerechte Bohrungen in den <a href="'+xpath+'dguv/101_008/4_4.htm">Spunddielen</a> herstellen';
m[x++]='22:Schrägzug nur dann, wenn in der Betriebsanleitung zugelassen (Einsatzgrenzen beachten!)';
m[x++]='23:Zur Aufnahme von Bohr- oder Rammelementen formschlüssige Lastaufnahmemittel verwenden';
m[x++]='24:Maßnahmen gegen Absturz beim Aufstieg = 2 m vorhanden';
m[x++]='25:Rammbären, Rammhauben, Rüttler usw. gegen Herabfallen sichern';
m[x++]='26:Einsatz von Mobilkränen für Zieharbeiten mit Rüttlern nur unter Beachtung der Zulassung des Herstellers für diese Arbeiten';
m[x++]='27:Sicherungsmaterial für Bohrpfahllöcher vorhanden';
m[x++]='28:Schwimmrammarbeiten von Pontons ausführen, deren Kippstabilität von einem Sachverständigen nachgewiesen wurde.';
m[x++]='29:Deckskanten des Pontons, soweit es der Betrieb zuläßt, gesichert.';
m[x++]='30:Rettungsmittel bei Schwimmrammarbeiten vorhanden';
m[x++]='31:Rettungskragen bei Arbeiten auf Pontons tragen';
m[x++]='32:Lastaufnahme, Transport und Einheben der Bewehrungskörbe entsprechend der Anweisung';
m[x++]='33:$<b>Mensch und Maschinen</b>';
m[x++]='34:Aufenthalt im Gefahrenbereich vermeiden (auch kippende oder herunterfallende Ramm-bzw. Bohrelemente beachten)';
m[x++]='35:Sicherung von Rammelementen gegen Umfallen';
m[x++]='36:Beseitigung von Lärmquellen z.B. Anschlagketten ';
m[x++]='37:Gehörschutz wird bereitgehalten und getragen';
m[x++]='38:Einsatz von Einweisern bei eingeschränkter Sicht des Maschinenführers';
m[x++]='39:Nutzung eines Personenaufnahmemittels bei der BG anmelden';
m[x++]='40:Absturzsicherungen auf beweglichen Plattformen vorhanden';
m[x++]='41:Verwendung entsprechender Lastaufnahmemittel für Ramm- bzw. Bohrelemente';
m[x++]='42:Mechanische Verriegelung (Absteck-oder Halteeinrichtung) beim Betreten des Bereiches unter der Rammausrüstung ';
m[x++]='43:Vermeidung von Staubentwicklung bei Bentonitanlagen (z.B. Schlitzwandarbeiten)';
m[x++]='62:$<b>Tägerbohlwand</b>';
m[x++]='44:Die <b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_trägerbohlwand\')"> Trägerbohlwände</a> wird eingesetzt';
m[x++]='45:Verbaurand bis 2 m &le; 5 cm, über 2 m > 10 cm';
m[x++]='46:Arbeitsräume in der Baugrube min. 50 cm';
m[x++]='47:Sicherung der Baugrubenkante gegen Absturz (z.B. 3-teiliger Seitenschutz)';
m[x++]='48:Standsicherheit des Verbaus in jedem Bauzustand';
m[x++]='49:Ausfachung liegt bei I-Trägern bei min. 1/5 und bei U-Profilen bei mindestens 2/5 der Flanschbreite (DIN 4124, 8.2.4)';
m[x++]='50:Ausfachung durch Hartholzkeile und Laschen gesichert';
m[x++]='51:Holzausfachung hat die Sortierklasse S10 (siehe DIN 4074-1)';
m[x++]='52:Vor dem Rückbau sind Informationen über Einbau und die Nutzungsdauer zu gewinnen';
m[x++]='53:vorauseilender Aushub max. 50 cm bei nichtbindigen Böden, max. 1,0 m bei bindigen Böden, max. 1 Ausfachungsbohle bei locker gelagerten Kiesen und Sanden';
m[x++]='54:$<b>Schlitzwände</b>';
m[x++]='55:Lastaufnahme, Transport und Einheben der Bewehrungskörbe entsprechend der Anweisung';
m[x++]='56:Sicherung der Schlitzwände gegen Hineinstürzen';
