datum[z]='141216';
titel[z]='Sprengarbeiten';
gefahr[z]='Gefährdungsfaktoren: Brand und Explosion; Lärm; Unkontrolliert bewegte Teile';
fragen[z]='Welche Maßnahmen werden gegen Gefährdungen bei Sprengarbeiten durchgeführt?';
m[x++]='00:Sprenganzeige mit genauen und umfassenden Angaben nach Ortsbesichtigung';
m[x++]='01:Zeitplanung/Zeitvorgaben mit Berücksichtigung äußerer Einflüsse (z.&nbsp;B. Zugpausen, Lichtverhältnisse, Jahreszeiten)';
m[x++]='02:bei Bedarf: Sachverständigen hinzuziehen';
m[x++]='03:Sprengberechtigte mit entsprechender Befähigung (z.&nbsp;B. für allgemeine Sprengarbeiten, Sprengungen von Bauwerken und Bauwerksteilen) einsetzen';
m[x++]='08:Baustatiker einschalten, sofern der Sprengberechtigte keine ausreichenden statischen Fachkenntnisse hat';
m[x++]='04:Sprenghelfer: <br>-mind. 18 Jahre <br>- zuverlässig <br>- körperlich geeignet';
m[x++]='05:Nur <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen. <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
m[x++]='06:Sprengsignale und Warnzeichen bei Sprengarbeiten sind festgelegt';
m[x++]='09:Abstand zur Sprengstelle festlegen';
m[x++]='14:Abschirmung (z.&nbsp;B. bei Bauwerkssprengung)';
m[x++]='15:Abdeckung';
m[x++]='11:Zündstromkreisberechnung und Zündstromkreisprüfung';
m[x++]='07:Auswahl ausreichend leistungsfähiger Zündmaschinen';
m[x++]='10:Sicherheitsabstand zu stromführenden Teilen und anderen Fremdenergien einhalten';
m[x++]='12:geeignete Hilfsmittel (z.&nbsp;B. Ladestöcke, Zangen, Messer)';
m[x++]='13:Sprengstoffe, Zündmittel und Zubehör mit BAM-Zulassung';
m[x++]='16:neue Schlagpatrone';
m[x++]='20:Temperatur der Laderäume beachten';
m[x++]='17:Gehörschutz';
m[x++]='19:Überprüfen des Sprengergebnisses';
m[x++]='18:Versager sichern';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten.';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt.';
