m=new Array();x=0;
ga_dateien['f_staub_allg']=z;
datum[z]='150801';
titel[z]='Tätigkeiten mit Staubentstehung';
gefahr[z]='Gefährdungsfaktoren: Stäube';
fragen[z]='Welche Maßnahmen werden getroffen beim Entstehen von <a href="'+xpath+'ga_bau/f_g/g6041.htm">Stäuben</a> beim Schneiden, Schleifen, Bohren, Stemmen, Fräsen, Sägen?';
hinweis_neu[z]='Bei Grenzwertüberschreitung bitte Maßnahmen überprüfen';
m[x++]='00:%Minimieren der Staubbelastung durch:';
m[x++]='02:staubarme Bearbeitungsverfahren (zum Beispiel Nassbearbeitung, langsam laufende Trennwerkzeuge, "Knabberzangen", beim Entleeren des Entstaubers Staubentwicklung vermeiden)';
m[x++]='01:Arbeitsbereiche abgrenzen (staubgefährdete Bereiche von übrigen Arbeitsplätzen trennen, einhausen)';
m[x++]='03:Auftretende Stäube direkt an der Entstehungsstelle <a href="'+xpath+'ga_bau/f_g/g6061.htm">absaugen</a> (ggf. <a href="'+xpath+'ga_bau/f_g/g6129.htm">Entstauber</a> Staubklasse M einsetzen)';
m[x++]='04:Staubniederschlagung durch Sprühnebel (Verbot von trockenem Kehren oder Abblasen mit Druckluft)';
m[x++]='05:Nur anhand der <a href="'+xpath+'ga_bau/f_g/g60281.htm">Betriebsanweisung</a> <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen. <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
