m=new Array();x=0;
ga_dateien['f_org_arbeitsorganisation']=z;
datum[z]='150807';
titel[z]='Wirkungsvolle Arbeitsorganisation';
gefahr[z]='Gefährdungsfaktoren: Mängel in der Arbeitsorganisation; Psychische Belastungen';
fragen[z]='Ziel: Die Arbeiten in unserem Unternehmen sind so geplant und organisiert, dass produktiv, sicher und gesund gearbeitet sowie gute Bauqualität geliefert werden kann.';
m[x++]='00:Die <a href="'+xpath+'ga_bau/f_vuh/vuh20010.htm">Verantwortlichkeiten</a> sowie die Entscheidungs- und Weisungsbefugnisse inklusive der Aufgaben zum Arbeitsschutz (<a href="'+xpath+'ga_bau/f_vuh/vuh20005.htm">Pflichtenübertragung</a>) sind festgelegt.<br><br>zum Beispiel Organigramm, <a href="'+xpath+'ga_bau/formular/ams/dok_3_5.doc">Stellen- und Aufgabenbeschreibungen</a><br><br><span onclick="umh(\'_42_44\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='01:Die Zusammenarbeit und die Schnittstellen zwischen den Abteilungen/Arbeitsbereichen im Unternehmen bei der Organisation der Arbeitsaufgaben sind festgelegt. <br><br>zum Beispiel zwischen Einkauf, Kalkulation, Arbeitsvorbereitung, Bauleitung und kaufmännischem Bereich, Verfahrensanweisungen und Prozessbeschreibungen';
m[x++]='02:Die Arbeitsabläufe werden regelmäßig nach <a href="'+xpath+'ga_bau/f_iop/iop0000.htm">Schwachstellen und Verbesserungsmöglichkeiten</a> analysiert und beurteilt (Qualitätskontrolle). Die festgelegten Verbesserungsmaßnahmen werden durchgeführt und kontrolliert.<br><br>zum Beispiel Gefährdungsbeurteilungen durchführen, Qualitätskontrolle, Prüfplan, Maßnahmenkataloge und Aktionsplan, <a href="'+xpath+'ga_bau/f_all/all01035.htm">Ideen-Treffen</a>';
m[x++]='03:Die Maßnahmen zur <a href="'+xpath+'ga_bau/f_iop/iop0341.htm">Sicherheit und Gesundheit bei der Arbeit</a> werden organisiert und durchgeführt.';
m[x++]='04:%zum Beispiel:';
m[x++]='05:<span class="einz">•</span> Die Durchführung der <a href="'+xpath+'help/ablauf.htm">Gefährdungsbeurteilungen</a> und die Kontrolle der durchgeführten Maßnahmen sind organisiert.';
m[x++]='06:<span class="einz">•</span> Die <a href="'+xpath+'ga_bau/f_iop/iop043.htm">sicherheitstechnische</a> und <a href="'+xpath+'ga_bau/f_iop/iop036_1.htm">betriebsärztliche</a> Betreuung ist festgelegt und umgesetzt.<br><br>zum Beispiel Regelbetreuung oder alternative Betreuungsmodelle – sich durch BG BAU beraten lassen<br><br><span onclick="umh(\'_52_01\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='07:<span class="einz">•</span> Die notwendigen <a href="'+xpath+'bausteine/a_004/a_004.htm">Erste-Hilfe-Maßnahmen</a> sind festgelegt.<br><br>zum Beispiel ausgebildete <a href="'+xpath+'dguv/1/26.htm">Ersthelfer</a> in ausreichender Anzahl, <a href="'+xpath+'tr/asr_a4_3/4.htm">Erste-Hilfe-Materialien</a> – sich durch <a href="'+xpath+'ga_bau/f_iop/iop039.htm">Fachkraft für Arbeitssicherheit</a> und <a href="'+xpath+'ga_bau/f_iop/iop036_1.htm">Betriebsarzt oder Betriebsärztin</a> beraten lassen<br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_ErsteHilfe_Brandschutz\')">Erste Hilfe und Brandschutz</a> wird zur Überprüfung verwendet.<br><br><span onclick="umh(\'_53_54_55\',this)"><a href="#">Umsetzungshilfen</a>';
m[x++]='08:<span class="einz">•</span> Die notwendigen <a href="'+xpath+'tr/asr_a2_2/titel.htm">Brandschutzmaßnahmen</a> sind festgelegt (<a href="'+xpath+'ga_bau/f_iop/iop046.htm">Brandschutzordnung</a>).<br><br>zum Beispiel geeignete, geprüfte und ausreichende Anzahl von <a href="'+xpath+'ga_bau/f_bue/bue90242.htm">Feuerlöschern</a> - sich durch <a href="'+xpath+'ga_bau/f_iop/iop039.htm">Fachkraft für Arbeitssicherheit</a> beraten lassen<br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_ErsteHilfe_Brandschutz\')">Erste Hilfe und Brandschutz</a> wird zur Überprüfung verwendet.';
m[x++]='28:<span class="einz">•</span> Die notwendigen Maßnahmen zur Prävention eines Traumas (etwa nach einem schweren Arbeitsunfall) sind festgelegt.<br><br>Zum Beispiel:<ul><li>Notfallplan</li><li>ausgebildete Helfer zur psychologischen Erstberatung</li></ul>';
m[x++]='09:<span class="einz">•</span> Maßnahmen zur betrieblichen Gesundheitsförderung sind organisiert und durchgeführt.<br><br>zum Beispiel zu Fehlzeiten, Stress, Ernährung';
m[x++]='10:<span class="einz">•</span> Maßnahmen bei Unfällen und Berufskrankheiten<br><br>zum Beispiel Unfallanzeigen, Berufskrankheitenanzeigen, Statistiken<br><br><span onclick="umh(\'_04_05_39\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='11:$<b>Weitere mögliche Prozesse und Maßnahmen:</b>';
m[x++]='12:Mit den Beschäftigten ist schriftlich vereinbart (zum Beispiel in Arbeitsverträgen, Arbeitsanweisungen), welche Arbeitsaufgaben sie haben und wie sie diese sicher und qualitätsbewusst umsetzen können (inklusive Verpflichtung zu sicherem und gesundem Arbeiten).';
m[x++]='13:Die Arbeitsaufgaben sind eindeutig formuliert. Die Führungskräfte haben die Anweisung, sich zu vergewissern, dass die Beschäftigten die Aufgaben verstanden haben und dass es keine ungeklärten Überschneidungen mit anderen Arbeitsaufgaben gibt.<br><br>zum Beispiel durch Stellenbeschreibung, Arbeits- und Verfahrensanweisung<br><br><span onclick="umh(\'_43\',this)"><a href="#">Umsetzungshilfe</a></span>';
m[x++]='14:Die Arbeitsaufgaben werden so organisiert, dass den einzelnen Beschäftigten ihren Befähigungen entsprechend ein möglichst großer Rahmen eigener Entscheidungen bei der Umsetzung der Aufgaben bleibt.<br><br>zum Beispiel Führen mit Zielen';
m[x++]='15:Die geeigneten Personen für Arbeiten mit besonderen Gefährdungen sind benannt.<br><br>zum Beispiel <a href="'+xpath+'bausteine/c_301/c_301.htm#aabbranw">Abbrucharbeiten</a>, bei Arbeiten in <a href="'+xpath+'ga_bau/f_ko/ko16023.htm">engen Räumen</a> <br><br><span onclick="umh(\'_29\',this)"><a href="#">Umsetzungshilfe</a></span>';
m[x++]='16:Es ist festgestellt, welche <a href="'+xpath+'ga_bau/f_all/all0053.htm">arbeitsmedizinischen Vorsorge</a> <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a> erforderlich sind, und sie sind veranlasst.<br><br>zum Beispiel sich durch <a href="'+xpath+'ga_bau/f_iop/iop036_1.htm">Betriebsarzt oder Betriebsärztin</a> beraten lassen<br><br><span onclick="umh(\'_58\',this)"><a href="#">Umsetzungshilfe</a></span>';
m[x++]='17:Die Maschinenführer sind schriftlich beauftragt.<br><br>zum Beispiel Gabelstaplerfahrer, Kranführer, Erdbaumaschinenführer<br><br><span onclick="umh(\'_22_45_46\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='18:Die Beschäftigten sind verpflichtet, Störungen (zum Beispiel Unfälle und Beinahe-Unfälle) und Gefahren im Arbeitsablauf dem Vorgesetzten zu melden. Es werden entsprechende Maßnahmen eingeleitet.<br><br>zum Beispiel Meldebogen für Unfälle und Beinaheunfälle verwenden, <a href="'+xpath+'ga_bau/f_all/all01035.htm">Ideen-Treffen</a><br><br><span onclick="umh(\'_04\',this)"><a href="#">Umsetzungshilfe</a></span>';
m[x++]='19:In Unternehmen über 20 Beschäftigte:<br><ul><li>Es ist ein <a href="'+xpath+'ga_bau/f_iop/iop034.htm">Arbeitsschutzausschuss</a> (ASA) gebildet. ASA-Sitzungen werden regelmäßig durchgeführt.<li><a href="'+xpath+'ga_bau/f_iop/iop041.htm">Sicherheitsbeauftragte</a> sind benannt und ausgebildet.</ul><br><span onclick="umh(\'_01_02_51\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='20:Für spezielle Tätigkeiten und Aufgaben sind <a href="'+xpath+'ga_bau/f_iop/iop020_1.htm">Beauftragte</a> ausgebildet und ernannt.<br><br>zum Beispiel <a href="'+xpath+'ga_bau/f_g/g601220.htm">Gefahrgutbeauftragter</a>, Abfallbeauftragter, Umweltbeauftragter, Sachkundiger nach MVAS<br><br><span onclick="umh(\'_49\',this)"><a href="#">Umsetzungshilfe</a></span>';
m[x++]='21:Die erforderlichen <a href="'+xpath+'ga_bau/f_e/e0002.htm">Maßnahmen des Arbeitsschutzes</a> werden dokumentiert.';
m[x++]='22:Sicherstellen, dass Notfallpläne vorhanden sind und Rettungsübungen durchgeführt werden.';
