datum[z]='141216';
titel[z]='Klare Zielsetzungen';
gefahr[z]='Gefährdungsfaktoren: Mängel in der Arbeitsorganisation; Psychische Belastungen';
fragen[z]='Ziel: Jeder Führungskraft und jedem Beschäftigten ist deutlich, dass in unserem Bauunternehmen <a href="'+xpath+'gv/arbschg/titel.htm">qualitätsbewusst und sicher</a> gearbeitet wird.';
m[x++]='00:Es gibt eine klare Zielsetzung im Unternehmen.<br><br><span onclick="umh(\'_40_41\',this)"><a href="#">Umsetzungshilfen</a></span>';
m[x++]='01:Die Zielsetzung ist mit den Beschäftigten und Führungskräften besprochen.<br><br>zum Beispiel in Mitarbeitergesprächen, Betriebsversammlung, <a href="'+xpath+'ga_bau/f_all/all01035.htm">Ideen-Treffen</a>';
m[x++]='02:Das Erreichen der Ziele wird regelmäßig kontrolliert.';
m[x++]='03:$<b>Weitere mögliche Prozesse und Maßnahmen:</b>';
m[x++]='04:Es ist mit den Führungskräften vereinbart, wie die Zielsetzungen des Unternehmens konkret umgesetzt werden sollen.<br><br>zum Beispiel in Besprechungen oder Arbeits- und Verfahrensanweisungen';
m[x++]='05:Die Zielsetzung ist mit den Beschäftigten schriftlich vereinbart.<br><br>zum Beispiel in Betriebsvereinbarungen oder Arbeits- und Verfahrensanweisungen<br><br>';
m[x++]='06:Die Zielsetzung und die Strategie sind im Unternehmen schriftlich festgelegt.<br><br>zum Beispiel in Leitlinien, Businessplan, Maßnahmenkatalog mit messbaren Zielen, Aktionsplan';
