datum[z]='141216';
titel[z]='Anlegen von Arbeitsplätzen und Verkehrswegen für Bauarbeiten in stationären Betrieben';
gefahr[z]='Gefährdungsfaktoren: Stolpern, Rutschen, Stürzen; Absturz; Erfasst und getroffen werden';
fragen[z]='Wie werden Gefährdungen beim Einrichten und Benutzen von Arbeitsplätzen und Verkehrswegen vermieden?';
m[x++]='01:$<b>Einrichtung</b>';
m[x++]='02:<a href="'+xpath+'ga_bau/f_all/all0001.htm">Verkehrswege</a> ausreichend tragfähig einrichten';
m[x++]='03:Schutz vor abrutschenden, herabfallenden Gegenständen, z.&nbsp;B.:<br>nicht übereinander arbeiten (Koordination); Schutzdächer oder Schutznetze zur Sicherung des gefährdeten Bereiches; Absperrung/Kennzeichnung des gefährdeten Bereiches';
m[x++]='04:<a href="'+xpath+'ga_bau/f_a/a10061.htm">Öffnungen und Kanten</a> sichern, z.&nbsp;B.:<br>absperren; abdecken; Seitenschutz/umwehren; Fanggerüst; Auffangnetze; für Anseilschutz geeignete Anschlagpunkte festlegen (z.&nbsp;B. bei kurzfristigen Arbeiten)';
m[x++]='05:Hindernisse, Verschmutzungen und/oder Rutschgefahren vermeiden, z.&nbsp;B.:<br>rutschhemmender Bodenbelag, keine Stolperstellen';
m[x++]='06:Türen und Tore sicher gestalten, z.&nbsp;B.:<br>Pendeltüren/Pendeltore haben Sichtfenster oder sind durchsichtig; Rolltore/Schiebetüren/Schiebetore gegen Ausheben/Zulaufen gesichert; keine Quetsch- und Scherstellen an kraftbetriebenen Türen/Toren';
m[x++]='07:Standsichere Aufstiege und Tritte einrichten';
m[x++]='08:Gruben und Gräben sicher gestalten, z.&nbsp;B.:<br>Absturzsicherung wie Abdeckungen, Geländer; stand- und trittsichere Aufstiege; zwei Treppen (mit Neigungswinkel <&nbsp;45°)';
m[x++]='09:Regale sicher gestalten, z.&nbsp;B.:<br>Standsichere Aufstellung; tragfähiger und ebener Untergrund; Aufbau- und Betriebsanleitung<br>Bei Hochregallager zusätzlich: Kennzeichnungen bei Feldlasten <&nbsp;200&nbsp;kg bzw. >&nbsp;1000&nbsp;kg; Aufstiege kennzeichnen';
m[x++]='10:Arbeitsplätze und Verkehrswege abgrenzen';
m[x++]='11:Elektrische Anlagen sicher gestaltet (nach DIN&nbsp;VDE&nbsp;0100), z.&nbsp;B.:<br>Anschlusspunkte mittels RCD';
m[x++]='12:Beleuchtung/Sicherheitsbeleuchtung einrichten';
m[x++]='13:Personen- und Fahrzeugverkehr trennen, z.&nbsp;B.:<br>getrennte Türen/Tore für Fußgänger und Fahrzeuge, Absperreinrichtungen, Kennzeichnung, Sicherheitsabstände einhalten';
m[x++]='14:Fahrordnung aufstellen (Gegenverkehr vermeiden)';
m[x++]='15:Ermitteln, welche Gefahrstoffe eingesetzt werden und welche Maßnahmen an Arbeitsplätzen und Verkehrswegen einzuhalten sind ';
m[x++]='16:$<b>Betrieb</b>';
m[x++]='17:Rückwärtsfahrten vermeiden oder falls erforderlich Einweiser oder Kamera einsetzen, z.&nbsp;B.:<br>Rückfahrtkontrollsystem';
m[x++]='18:Sicherstellen, dass Verkehrswege freigehalten werden, z.&nbsp;B.<br>keine Gegenstände/Materialien lagern';
m[x++]='19:Beleuchtungskörper regelmäßig reinigen und warten';
m[x++]='20:Bei Regalen/im Lager stehen Tritte oder Stufenleitern in ausreichender Anzahl bereit.';
m[x++]='21:Sicherstellen, dass Regale sicher betrieben werden, z.&nbsp;B.:<br>zulässige Belastung bekannt gemacht und eingehalten; übersichtliche Lagerung; Lagergut vor Herabfallen sichern; spezielle Regelungen zur Gefahrstofflagerung beachtet.';
m[x++]='22:Witterungseinflüsse beachten (z.&nbsp;B. Nässe, Frost)';
m[x++]='23:$<b>Instandhaltung</b>';
m[x++]='24:Prüfende Person und Prüffristen für die Prüfung von Arbeitsplätzen und Verkehrswegen sowie den technischen Einrichtungen in diesen Bereichen (z.&nbsp;B. Türen/Tore) sind festgelegt.';
m[x++]='25:Prüfende Person (Elektrofachkraft) und Prüffristen für die Prüfung von elektrischen Anlagen und Betriebsmittel sind festgelegt.';
m[x++]='26:$<b>Einrichtung von Sanitär und Sozialräumen</b>';
m[x++]='27:<a href="'+xpath+'tr/asr_a4_1/6.htm">Waschräume einrichten</a>.';
m[x++]='28:<a href="'+xpath+'tr/asr_a4_1/5.htm">Toiletten einrichten</a>.';
m[x++]='29:<a href="'+xpath+'tr/asr_a4_1/7.htm">Umkleideräume einrichten</a>.';
m[x++]='30:Regelmäßige Reinigung der Sozialeinrichtungen organisieren';
m[x++]='31:<a href="'+xpath+'tr/asr_a4_2/4.htm">Pausenraum</a> ab 10 Beschäftigten oder wenn Sicherheits- oder Gesundheitsgründe dies erfordern, einrichten.';
