m[x++]='05:<a href="'+xpath+'ga_bau/f_ubm/ubm4059.htm">regelmäßiges</a> Überprüfen von <a href="'+xpath+'ga_bau/f_ubm/ubm40481.htm">Schutzeinrichtungen</a> sicherstellen';
m[x++]='06:<a href="'+xpath+'ga_bau/f_all/all0052.htm">Beschäftigungsbeschränkungen</a> für Jugendliche beachten';
m[x++]='12:Nur Druckluftbehälter einsetzen, deren Prüffrist nicht abgelaufen ist.';
m[x++]='13:Nur gekennzeichnete, mit einem Fabrikschild versehene <a href="'+xpath+'bausteine/b_237/b_237.htm">Verdichter/Druckbehälter</a> verwenden.';
m[x++]='14:Auf funktionsfähige Sicherheitsventile und Druckmessgeräte achten.';
m[x++]='15:Sicherheitsventile nicht durch Absperreinrichtungen unwirksam machen.';
m[x++]='16:Sicherheitsventile/Druckmessgeräte gegen Beschädigungen schützen.';
m[x++]='17:Instandhaltung der <a href="'+xpath+'bausteine/b_237/b_237.htm">Verdichter/Druckbehälter</a> nur durch Fachkundige Personen';
m[x++]='18:Elektrisch betriebene Verdichter nur über Übergabe-/Anschlusspunkte (<a href="'+xpath+'ga_bau/f_ea/ea500912.htm">RCD</a>) anschließen.';
m[x++]='19:Nur Druckbehälter verwenden die vor der ersten Inbetriebnahme geprüft wurden.';
m[x++]='20:Prüffristen gemäß Herstellerangaben, Gefährdungsbeurteilung und Betriebssicherheitsvorschrift ermitteln.';
