gefahr[z]='Gefährdungsfaktoren: Stolpern, Rutschen, Stürzen; Absturz; Unkontrolliert bewegte Teile; Dehydration';
fragen[z]='Welche Maßnahmen werden gegen Gefährdungen beim seilunterstützten Arbeiten für den Höhenarbeiter getroffen?';
hinweis_neu[z]='Veränderte Vorgaben zur arbeitsmedizinischen Vorsorge, bitte Maßnahmen überprüfen';
m[x++]='01:Geeignete, ausgebildete Beschäftigte einsetzen.';
m[x++]='22:Auf Wunsch des Beschäftigten ist eine arbeitsmedizinische Vorsorge, zu ermöglichen. <br />Hinweis_1: Diese Maßnahmenzeile wird so nicht mehr unterstützt. Bitte hier klicken, dann die Inhalte in geeignete Maßnahmenzeilen dieses Auswahlbogens übertragen. Danach die Inhalte dieser Zeile komplett löschen, auch die Checkboxen.';
m[x++]='02:Für die Dauer der Arbeiten geeignete, geprüfte und gekennzeichnete Arbeitsmittel einsetzen (die Dauer der Arbeiten berücksichtigen).';
m[x++]='03:Mitgeführtes Werkzeug und Material sichern; dabei Gewicht und Windangriff berücksichtigen.';
m[x++]='04:Gefahrbereich unterhalb der Montagearbeiten und die Bereiche der Anschlagpunkte sowie Seilstrecken sperren und sichern.';
m[x++]='05:Einflüsse durch Witterung berücksichtigen, z.&nbsp;B. keine Arbeiten bei Gewitter, Sturm, Vereisung.';
m[x++]='06:Zugangsregelungen zu den Arbeitsplätzen festlegen (Sicherungen für horizontale Bewegungen vorsehen z.&nbsp;B. Lifelines).';
m[x++]='07:<a href="'+xpath+'ga_bau/formular/BA_Masch/BA_ABSTU.doc">Betriebsanweisung erstellen</a>.';
m[x++]='08:Nur anhand der <a href="'+xpath+'ga_bau/f_g/g60281.htm">Betriebsanweisung</a> <a href="'+xpath+'ga_bau/f_g/g60291.htm">unterwiesene</a> Beschäftigte einsetzen. <a href="'+xpath+'ga/db.htm?data0"><img src="../grafik/n.gif"></a>';
m[x++]='09:Auffanggurt mit energieabsorbierendem Verbindungsmittel (<a href="'+xpath+'dguv/112_198/6.htm">Falldämpfer) benutzen.';
m[x++]='10:Tragsystem verwenden.';
m[x++]='11 Sicherungssystem verwenden.';
m[x++]='12:Objektbezogenes Rettungskonzept mit Notfallmaßnahmen vorsehen, z.&nbsp;B. 2.&nbsp;Seilstrecke, Rettungssack.';
m[x++]='13:Keine <a href="'+xpath+'dguv/100_001/2.htm#2.7.2">Alleinarbeit</a>!';
m[x++]='14:Angepasste persönliche Schutzausrüstung einsetzen (z.B. Industrieschutzhelm nach DIN&nbsp;EN&nbsp;397 - für die Baustelle geeignet).';
m[x++]='15:Gegen Dehydrierung Getränke vorhalten.';
m[x++]='16:Kommunikationseinrichtungen bereitstellen und benutzen.';
