datum[z]='141216';
titel[z]='Arbeitsplätze für Taucher/Taucherin, Signalmann, Reservetaucher und Taucherhelfer';
gefahr[z]='Gefährdungsfaktoren: Sturz ins Wasser; Stolpern, Rutschen, Stürzen';
fragen[z]='Welche Maßnahmen werden getroffen, um sichere Arbeitsplätze für Taucher/Taucherin, Signalmann, Reservetaucher und Taucherhelfer zu schaffen?';
m[x++]='00:Der Arbeitsplatz des Tauchers/der Taucherin ist den Verhältnissen entsprechend ergonomisch <br><br>zum Beispiel durch Aufbau eines Arbeitsgerüstes/einer Arbeitsplattform unter Wasser mit Zugang über eine Leiter. Ausreichend tragfähigen Arbeitsstuhl bereitstellen.';
m[x++]='01:Der Signalmann hat einen sicheren und geeigneten Arbeitsplatz. <br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_signal_reserve_helfer\')"> "Arbeitsplatz Signalmann, Reservetaucher, Taucherhelfer"</a> verwenden.';
m[x++]='02:Der Reservetaucher/die Reservetaucherin hat einen sicheren Arbeitsplatz, der einen sofortigen Einsatz ermöglicht. <br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_signal_reserve_helfer\')"> "Arbeitsplatz Signalmann, Reservetaucher, Taucherhelfer"</a> verwenden.';
m[x++]='03:Der Taucherhelfer hat einen sicheren und geeigneten Arbeitsplatz. <br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_signal_reserve_helfer\')"> "Arbeitsplatz Signalmann, Reservetaucher, Taucherhelfer"</a> verwenden.';
