ga_dateien['f_tauch_pontons']=z; // Diese Maske bedarf der Überarbeitung 05.08.2016
datum[z]='141216';
titel[z]='Einsatz von Pontons (<a href="'+xpath+'dguv/64/titel.htm">schwimmende Geräte)';
gefahr[z]='Gefährdungsfaktoren: Sturz ins Wasser; Unkontrolliert bewegte Teile';
fragen[z]='Welche Maßnahmen werden getroffen, um Pontons (schwimmende Geräte) sicher einsetzen zu können?';
m[x++]='00:Die erforderlichen Verkehrszulassungen sind vorhanden.<br><br>Überprüfung gemäß der örtlich gültigen Schifffahrtverordnung; Anfrage bei zuständiger Behörde (WSD)';
m[x++]='01:Die Schwimmfähigkeit für die vorgesehene Belastung ist gewährleistet. <br><br>Zum Beispiel: gültige geprüfte Stabilitätsberechnung überprüfen; im Ausnahmefall (Kurzeinsatz) Belastungsprobe durch Sachverständigen; zulässige Krängung nicht überschreiten, Kennzeichnung der Restfreiborde; Überprüfung der Schotten auf Dichtigkeit; Überprüfung der Lenzeinrichtungen';
m[x++]='02:Es ist sichergestellt, dass der Ponton die ausreichende Größe und Tragfähigkeit besitzt.';
m[x++]='03:Es ist sichergestellt, dass das notwendige Arbeitsgerät vorhanden ist.';
m[x++]='04:Es ist sichergestellt, dass die Ausrüstung sicher befestigt ist.';
m[x++]='05:Es ist sichergestellt, dass der Ponton sicher eingesetzt wird. <br><br><b>Checkliste</b> <a href="javascript:checkliste(\'f_cl_ponton\')"> "Ponton sicher betreiben"</a>';
