fragen[z]='Welche Maßnahmen zur Verminderung allgemeiner Risiken werden ergriffen?';
m[x++]='01:Besondere Erschwernisse durch Unterwassersprengarbeiten - gegenseitige Sprechverbindung einsetzen';
m[x++]='02:Besondere Erschwernisse durch Strömung >&nbsp;1,5&nbsp;m/s - gegenseitige Sprechverbindung einsetzen';
m[x++]='03:Besondere Erschwernisse durch Arbeiten in/unter Wracks/Bauwerken/Rohren/Pfahlrosten <br>- gegenseitige Sprechverbindung einsetzen';
m[x++]='04:Besondere Erschwernisse durch Gefahr des Verhakens - gegenseitige Sprechverbindung einsetzen';
