fragen[z]='Welche Maßnahmen sind zur Vermeidung von Gefährdungen bei Unterwasserschweißarbeiten durchzuführen?';
m[x++]='01:Auswahl geeigneter Beschäftigter (u.a. Schweißbescheinigung)';
m[x++]='02:Baustromverteiler sind von einer Elektrofachkraft anzuschließen und regelmäßig zu prüfen (<a href="'+xpath+'ga_bau/f_ea/ea50172.htm">PRCD-S</a>).';
m[x++]='03:Beim Elektrodenwechsel Strom allpolig abschalten';
m[x++]='04:Beim Schweißen/Schneiden wird die Funkverbindung gestört (Leinenzugsignale sind zu vereinbaren).';
m[x++]='05:Der Strom darf nur auf Weisung des Tauchers ein- oder ausgeschaltet werden.';
m[x++]='06:Die Tauchausrüstung muss so ausgelegt sein, dass keine Spannungsbrücken entstehen (Gummiisolierung der Metallteile, isolierende Schichten).';
m[x++]='07:Nur zugelassene Schweißtrafo verwenden';
m[x++]='08:Schweißgleichrichter mit einer Leerlaufspannung bis 65&nbsp;V verwenden';
m[x++]='09:Zeitliche Begrenzung der Arbeiten in Zwangshaltung';
