titel[z]='Tauchen an Wracks / Wrackbergung';
gefahr[z]='Gefährdungsfaktoren: Sturz ins Wasser; Unkontrolliert bewegte Teile';
fragen[z]='Wie können Gefährdungen bei Arbeiten an einem Wrack vermieden werden?';
m[x++]='01:Zur Vorbereitung des Wracktauchgangs sind die Schiffspläne einzusehen. Die Lage, die Positionierung und das Trümmerfeld sind zu erkunden.';
m[x++]='02:Bei der Erkundung eines Wracks ist auf Beschädigungen des Schiffskörpers zu achten, so dass die Atemluftversorgung des Tauchers bei Arbeiten nicht beschädigt wird.';
m[x++]='03:Die Schlauchleine muss auf Fühlung gehalten werden.';
m[x++]='04:Scharfe Kanten müssen entfernt oder verkleidet werden.';
m[x++]='05:Eventueller zusätzlicher Einsatz eines Sicherungstauchers bei tieferen Vorstößen ins  Wrackinnere. Er achtet u.a. darauf, dass die Schlauchleine nicht beschädigt wird.';
m[x++]='06:Einsatz von Unterwasserfahrzeugen (ROV) zum Erkunden und für UW-Arbeiten.';
m[x++]='07:$<b>Arbeiten mit Auftriebskörpern </b>';
m[x++]='08:Anhand der Pläne muss der Bergungsfachmann die Größe und Positionierung der Hebesäcke bestimmen.';
m[x++]='09:Siehe Tauchausrüstung - Lifting Equipment (Liftingbag)/Hebesäcke';
m[x++]='10:Zusätzliche Maßnahmen';
