ga_dateien['f_tauch_notfall']=z; // SEHR VIEL EIGENTLICH CHECKLISTE 08.08.2016
datum[z]='141216';
titel[z]='Notfallplanung für Taucherarbeiten';
gefahr[z]='Gefährdungsfaktoren: Mängel in der Arbeitsorganisation';
fragen[z]='Welche Maßnahmen werden getroffen für Notfälle bei Taucherarbeiten?';
m[x++]='01:$<b>Erste Hilfe Material</b>';
m[x++]='03:Überprüfung des Verbandmaterials bezüglich dessen Verfallsdatum';
m[x++]='02:Verbandmaterial (<a href="'+xpath+'tr/asr_a4_3/4.htm">nach ASR 4.3</a>) in Abhängigkeit von der Anzahl der Beschäftigten an der Tauchstelle bereithalten.';
m[x++]='04:Erste-Hilfe-Material in Abhängigkeit von der Arbeitsaufgabe bereitstellen (z.&nbsp;B. Augenspülflasche, Kühlkompressen, Wärmeschutzfolie).';
m[x++]='05:$<b>Sauerstoffatemstelle</b>';
m[x++]='06:Bereitstellen eines Sauerstoff-Atemgerätes, das Atmen von reinem Sauerstoff für mindestens 3&nbsp;Stunden gewährleistet.';
m[x++]='07:Unterweisung der Mitglieder der Tauchgruppe:<br>- Handhabung des Sauerstoff-Atemgerätes';
m[x++]='08:Nur medizinischen Sauerstoff verwenden.';
m[x++]='09:Klären, wo im Bedarfsfall weiterer medizinischer Sauerstoff bezogen werden kann.';
m[x++]='10:$<b>Ersthelfer</b>';
m[x++]='11:"Über Wasser" steht ständig ein einsatzbereiter Ersthelfer mit erweiterten Kenntnissen für Tauchunfälle zur Verfügung.';
m[x++]='12:Wenn Taucher und Reservetaucher Ersthelfer sind, noch einen weiteren Ersthelfer an der Tauchstelle bereithalten.';
m[x++]='13:Ersthelfertraining spätestens nach 24 Monaten';
m[x++]='14:Regelmäßige Schulung der gesamten Tauchgruppe in der Herz-Lungen-Wiederbelebung';
m[x++]='15:Unterweisung aller Mitglieder der Tauchgruppe:<br>- Sofortmaßnahmen nach Tauchunfällen';
m[x++]='16:Rettungsübung durchführen.';
m[x++]='18:$<b>Taucherarzt</b>';
m[x++]='19:Fachkundigen Arzt ermitteln und durch Aushang an der Tauchstelle (Name, Adresse, Erreichbarkeit) bekanntgeben [www.gtuem.org]';
m[x++]='20:Erreichbarkeit eines fachkundigen Arztes außerhalb der üblichen Sprechzeiten ermitteln/abstimmen.';
m[x++]='21:$<b><a href="'+xpath+'dguv/40/5.htm">Taucherdruckkammer</b>';
m[x++]='22:Druckkammer bereitstellen, wenn: Austauchzeit >35 min oder Tauchtiefe >10 m, wenn die nächste Taucher-Druckkammer nicht binnen 3 Stunden erreichbar ist.';
m[x++]='24:Druckkammer bereitstellen, die einen Überdruck von mind. 5 bar ermöglicht';
m[x++]='25:Überdruck von 5 bar muss nach spätestens 6 Minuten erreichbar sein';
m[x++]='26:Sicht- und Sprechverbindung mit den Personen in der Kammer muss möglich sein';
m[x++]='27:Sauerstoffatmung muss in der Kammer möglich sein';
m[x++]='28:Unabhängiges Ein- und Ausschleusen von Personen muss möglich sein';
m[x++]='29:Ausreichenden Luftvorrat für das Erreichen des Überdrucks und für eine ausreichende Spülung bereitstellen';
m[x++]='30:Abstimmung der Maßnahmen zur Rekompression mit dem fachkundigen Arzt';
m[x++]='31:Unterweisung des Personals:<br>- Handhabung/Bedienung der Taucher-Druckkammer';
m[x++]='32:Unterweisung des Personals:<br>- Rekompressions-Tabellen/ärztlicher Rekompressionsplan';
m[x++]='33:Nächste betriebsbereite Taucher-Druckkammer ermitteln (24-h Bereitschaft)';
m[x++]='34:Erreichbarkeit des Bedienpersonals sicherstellen (24-h Bereitschaft)';
m[x++]='35:Ermitteln der Transportmöglichkeiten zur nächsten betriebsbereiten Taucher-Druckkammer unter Berücksichtigung der besonderen Bestimmungen für Flüge';
m[x++]='36:$<b>Notrufeinrichtungen</b>';
m[x++]='37:Bereitstellen von Notrufeinrichtungen (Telefon, Funk) - Ladezustand beachten';
m[x++]='38:Überprüfung der sicheren Netz-Verfügbarkeit bei Mobiltelefonen';
m[x++]='39:Festlegen, dass der Tauchgang abzubrechen ist, wenn die Notrufeinrichtung ausfällt';
m[x++]='40:Ausbildung des Personals für Seefunk';
m[x++]='41:Aushang der Notrufnummern bezüglich der Aktualität prüfen';
m[x++]='42:$<b>Rettungsweg (An- und Abfahrt)</b>';
m[x++]='43:Kennzeichnung der Zufahrtswege abseits gelegener Tauchstellen für Rettungsdienste';
m[x++]='44:Abstimmung von Lotsenpunkten mit den zuständigen Rettungsleitstellen';
m[x++]='45:Abstimmung besonderer Anforderungen an die Einsatzfahrzeuge mit den Rettungsleitstellen (z.&nbsp;B. Bodenfreiheit, Durchfahrtsbreiten)';
m[x++]='46:Abstimmung und Festlegung von Hubschrauber-Landeplätzen mit den Rettungsleitstellen';
m[x++]='47:Befahrbarkeit der Rettungswege überprüfen';
m[x++]='48:Bei Nicht-Befahrbarkeit alternative Rettungswege ermitteln und mit den Rettungsdiensten abstimmen';
m[x++]='49:$<b>Besondere Rettungseinrichtungen</b>'; //was sind besondere Rettungseinrichtungen? 25.07.2016
m[x++]='50:Ermitteln der notwendigen Einrichtungen';
m[x++]='51:Bereitstellung der Einrichtungen und Unterweisung des Personals in der Handhabung';
m[x++]='52:Organisation notwendiger regelmäßiger Prüfungen (inkl. Dokumentation)';
