datum[z]='141216';
titel[z]='Arbeitsverhältnisse an der Tauchstelle';
gefahr[z]='Gefährdungsfaktoren: Gefahrstoffe; Erfasst und getroffen werden; Mängel in der Arbeitsorganisation';
fragen[z]='Wie werden Gefährdungen durch die besonderen Arbeitsverhältnisse an der Tauchstelle vermieden?';
m[x++]='01:$<b>Strömung/Gezeiten</b>';
m[x++]='02:Absprache mit Betreibern von künstlichen Einbauten im Gewässer (Wehre, Auslässe, Saugleitungen ...)';
m[x++]='03:Durchführen von Sicherungsmaßnahmen (z. B. Stromschutzschild)';
m[x++]='04:Sicherstellen, dass keine Gegenstände, die den Taucher gefährden können, an die Tauchstelle getrieben werden können. (Treibholz, sonstige Gegenstände, Eis.';
m[x++]='05:Abstimmen der Tauchgänge auf den Tidenhub';
m[x++]='06:$<b>Sichtverhältnisse</b>';
m[x++]='07:Ausrüstung mit geeigneten Leuchten';
m[x++]='08:Einüben der erforderlichen Arbeiten über Wasser, ggf. an Modell.';
m[x++]='09:Einmessen des Arbeitsbereiches';
m[x++]='10:$<b>Gefährdungen durch Gewässerkontamination</b>';
m[x++]='11:Überprüfung der vom Auftraggeber zur Verfügung gestellten Ergebnisse der Gewässererkundung, ggf. Anfordern dieser Ergebnisse';
m[x++]='12:Festlegen und Durchführen der in der <a href="'+xpath+'dguv/201_034/titel.htm">DGUV-I 201-034 "Tauchen in kontaminiertem Wasser"</a> festgelegten Maßnahmen';
m[x++]='13:$<b>Gefährdungen durch Schiffs-/Bootsverkehr</b>';
m[x++]='14:Absprache mit der zuständigen Stelle, z.B. Wasserschutzpolizei,  WSA, Hafenamt, Talsperrenverband.';
m[x++]='15:Kennzeichnen der Tauchstelle in Absprache mit der o.g. Stelle.';
m[x++]='16:Festlegen von Notfallmaßnahmen bei gefährlicher Schiffsannäherung ';
m[x++]='17:$<b>Gefährdungen durch lose, aufschwimmende Gegenstände</b>';
m[x++]='18:Berücksichtigung der schlagartig erhöhten Auftriebskraft beim Anheben von auf Grund liegenden Gegenständen (Hebesack)';
m[x++]='19:Fixieren von lockeren Gegenständen';
m[x++]='20:Fixieren von abzutrennenden Bauteilen o.ä. (Brennarbeiten)';
m[x++]='21:$<b>Gefährdungen durch Absturz</b>';
m[x++]='22:Sicherung der Absturzstellen';
m[x++]='23:Ausrüsten des Tauchers mit einem Harness und straffe Leinenführung';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten.';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt.';
