datum[z]='141216';
titel[z]='Empfangsdienste';
gefahr[z]='Gefährdungsfaktoren: Psychische Belastungen; Mängel in der Arbeitsorganisation';
fragen[z]='Wie werden Gefährdungen bei der Arbeit am Empfang vermieden?';
m[x++]='01:Die Arbeitsabläufe, Aufgabenverteilungen, Arbeitszeit- und Pausenregelungen sind allen Beschäftigten bekannt. Bei Problemen können sich die Beschäftigten an einen Vorgesetzten wenden, um Lösungen zu finden.';
m[x++]='02:Anhand der Checkliste "<a href="'+xpath+'ga_bau/formular/ab02.htm">Büroarbeitsplätze</a>" werden die Arbeitsplätze regelmäßig überprüft, um Belastungen zu minimieren und optimal arbeiten zu können.';
m[x++]='03:Die Arbeitsplätze sind ergonomisch gestaltet, ausreichend beleuchtet und frei von Zugluft. Die Raumakustik ermöglicht eine gute Verständigung.';
m[x++]='04:Die Beschäftigten tragen bequeme, rutschfeste Schuhe mit niedrigen Absätzen und ausreichend großer Auftrittfläche.';
m[x++]='05:Die Arbeits- und Gästebereiche im Empfang sind sauber. Verunreinigungen und Mängel auf Wegen, in Aufzügen, bei Dekorationen werden umgehend beseitigt.';
m[x++]='06:Verkehrswege werden freigehalten und Stolperstellen beseitigt. Fluchtwege und Notausgänge sind niemals verstellt.';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
