m=new Array();x=0;
ga_dateien['f_uv_strahlung']=z;
datum[z]='170317';
titel[z]='Arbeiten im Freien unter natürlicher UV-Strahlung und Hitze';
gefahr[z]='Gefährdungsfaktoren: Strahlung; Hitze, Klima';
fragen[z]='Welche Maßnahmen werden getroffen, um sich vor der schädlichen Wirkung <a href="'+xpath+'ga_bau/f_s/s130021.htm">natürlicher UV-Strahlung</a> zu schützen, die <a href="'+xpath+'ga_bau/f_s/s13014.htm">Belastungen durch Hitze</a> zu minimieren und <a href="'+xpath+'ga_bau/f_s/s130022.htm">Hitzeerkrankungen</a> zu vermeiden?';
m[x++]='00:Der aktuelle <a href="'+xpath+'ga_bau/f_s/s130024.htm">UV-Index</a> und die erwarteten Temperaturhöchstwerte wurden in Erfahrung gebracht (z.B. durch Wetter-App, Internet, TV)';
m[x++]='01:<a href="'+xpath+'ga_bau/f_s/s130025.htm">Unterweisung</a> der Beschäftigten über die Gefährdungen durch natürliche UV-Strahlung und die dazu festgelegten <a href="'+xpath+'ga_bau/f_s/s130027.htm">Schutzmaßnahmen</a>';
m[x++]='02:$<b>Gemäß festgestelltem UV-Index:</b>';
m[x++]='03:Das Arbeiten in der prallen Sonne wird möglichst vermieden (Arbeiten in den Schatten verlegen oder Beschattung der Arbeitsplätze durch Überdachungen, Sonnensegel, Sonnenschutzzelte oder spezielle Sonnenschirme).';
m[x++]='04:Die Arbeitszeit wird den besonderen Gegebenheiten angepasst, z.B. Verschiebung des Arbeitsbeginns in die Morgenstunden.'; 
m[x++]='05:Für die Pausen sind schattige bzw. überdachte Einrichtungen vorhanden.';
m[x++]='06:<a href="'+xpath+'ga_bau/f_s/s130028.htm">körperbedeckende Kleidung</a>';
m[x++]='07:<a href="'+xpath+'ga_bau/f_s/s130029.htm">Helm oder Kopfbedeckung</a> mit ausreichendem Schutz für Nacken und Ohren'; 
m[x++]='08:Sonnenschutzbrille (entsprechend DIN EN 166 und DIN EN 172: Schutzstufe 5-2, 6-2 oder 5-2,5 bzw. 6-2,5)'; 
m[x++]='09:ggf. Sonnenschutzmittel für unbedeckte Körperpartien (Lichtschutzfaktor &#8805; 30)';
m[x++]='12:$<b>Zusätzliche Maßnahmen bei Hitze:</b>';
m[x++]='13:Arbeitsplätze und Tätigkeiten, bei denen Hitze zu einer Gefährdung der Gesundheit führen kann, wurden ermittelt';
m[x++]='14:Die aktuellen bzw. die für die nächsten Tage prognostizierten Temperaturwerte werden bei der Arbeitsplanung berücksichtigt';
m[x++]='15:Die für diese aktuellen Wetterbedingungen notwendigen Schutzmaßnahmen wurden festgelegt und organisiert.';
m[x++]='16:Es erfolgt aktuell eine zusätzliche <a href="'+xpath+'ga_bau/f_s/s130032.htm">Unterweisung </a>der Mitarbeitenden zu den Symptomen von <a href="'+xpath+'ga_bau/f_s/s130022.htm">Hitzeerkrankungen</a> und zu <a href="'+xpath+'ga_bau/f_s/s130023.htm">Erste- Hilfe- Maßnahmen</a>';
m[x++]='17:Beratung durch den Betriebsarzt, ob <a href="'+xpath+'ga_bau/f_s/s130031.htm">Angebotsvorsorge</a>  zur Vermeidung von Hitzefolgen erforderlich ist.';
m[x++]='18:Das Aufheizen von Fahrerkabinen (z.B. Krane, Erdbaumaschinen) durch direkte Sonneneinstrahlung wird vermieden (z.B. Klimaanlage).';
m[x++]='19:Schaffung von kühlen Pausenbereichen ggf. klimatisierten Pausenräumen';
m[x++]='20:Erhöhung von Anzahl und Länge der Pausen';
m[x++]='21:Verringerung der körperlichen Anforderungen der Arbeit, z.B. verstärkter Einsatz von technischen Hilfsmitteln, keine Leistungslohnsysteme für körperlich schwere Arbeiten in Hitzeperioden, evtl. Einsatz zusätzlicher Hilfskräfte.';
m[x++]='22:Bereitstellung von Getränken (kalorienarm und alkoholfrei, z.B. Mineralwasser, möglichst ohne Kohlensäure oder ungesüßter Kräutertee); regelmäßige Trinkpausen sind möglich und sichergestellt (ca. alle 20 min.)';
m[x++]='23:Bereitstellung von <a href="'+xpath+'ga_bau/f_s/s130026.htm">Kühlkleidung</a>';
m[x++]='24:Sicherstellung einer (gegenseitigen) Überwachung des Befindens der Mitarbeitenden (z.B. Schwäche, Schwindel, Übelkeit)';
m[x++]='25:Eine <a href="'+xpath+'ga_bau/f_s/s130033.htm">Akklimatisierungsphase</a> für neue Mitarbeitenden ist sichergestellt, auch bei Rückkehrern aus einer Krankheitsphase';
