titel[z]='Brunnenbauarbeiten';
gefahr[z]='Gefährdungsfaktoren: Absturz; Klima; Gefahrstoffe; Erfasst und getroffen werden; Mängel in der Arbeitsorganisation';
fragen[z]='Welche Maßnahmen werden getroffen, um Gefährdungen bei Brunnenbauarbeiten zu vermeiden?';
m[x++]='00:offene Brunnen / Bohrungen / Schlitze abdecken oder umwehren';
m[x++]='01:Betreten von Brunnen, Bohrungen, Schächten nur wenn Standsicherheitsnachweis geführt ist.';
m[x++]='02:Verkehrssicherung bei Arbeiten im öffentlichen Straßenraum';
m[x++]='03:Werkzeuge und längenorientierte Einbauteile mechanisch führen ';
m[x++]='04:Für Bohrarbeiten in kontaminierten Bereichen spezielle Gefährdungsbeurteilung anfertigen. ';
m[x++]='05:Die erforderlichen Erste-Hilfe-Maßnahmen und Brandschutz-Maßnahmen für Räume unter Erdgleiche/ untertägige Räume sind umgesetzt.';
m[x++]='06:Bei Gefährdung durch Wasserandrang spezielle Flucht- und Rettungsmaßnahmen planen.';
m[x++]='07:Bei Steigeisengängen Auffanggurt und tragfähige Anschlageinrichtung (z.B. Dreibock) einsetzen.';
m[x++]='08:Werkzeuge und längenorientierte Einbauteile mechanisch führen';
m[x++]='09:Bei herabfallenden Einbauteilen in Brunnen, Bohrungen, Schächten: gesicherten Bereich aufsuchen';
m[x++]='10:Besondere Schutzmaßnahmen in engen Räumen';
m[x++]='11:Belüftung in Räumen unter Erdgleiche / untertägigen Räumen zur Verhinderung explosionsfähiger Atmosphären'; 
m[x++]='12:Einsatz druckluftbetriebener Arbeitsmittel';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten.';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt.';
