datum[z]='170626';
titel[z]='Rigg: Aufbau/Abbau';
gefahr[z]='Gefährdungsfaktoren: Unkontrolliert bewegte Teile; Absturz; erfasst und getroffen werden';
fragen[z]='Welche Maßnahmen werden ergriffen, um das Rigg sicher auf- und abzubauen?';
m[x++]='00:Dokumentation von Aufbaureihenfolge und Restriktionen beachten';
m[x++]='01:Gewerke informieren und den abgestimmten Aufbauablauf koordinieren';
m[x++]='02:Qualifiziertes Personal unterweisen';
m[x++]='03:<a href="'+xpath+'ga_bau/f_a/a1061.htm">Einschlägige Handlungshilfen</a> beachten';
m[x++]='04:Arbeitsbereiche absperren ggf. überwachen';
m[x++]='05:PSA gegen Absturz und Lifelines verwenden';
m[x++]='06:Safeties für Werkzeuge am Gurt befestigen';
m[x++]='07:$<b>Übersicht beim Bewegen komplexer Riggteile</b>';
m[x++]='08:Freie Kommunikationswege schaffen ggf. Kameraüberwachung';
m[x++]='09:Gruppenabschaltung bzw. zusätzliche Notabschaltung vorsehen';
m[x++]='10:Zentralen Steuerstand richtig positionieren';
m[x++]='11:Ausreichende Beleuchtung';
m[x++]='12:$<b>Überschneidung von Verfahrbereichen</b>';
m[x++]='13:Kommandostruktur mit Erstellern weiterer fliegender Bauten vereinbaren';
m[x++]='14:Eindeutig festgelegte Signale beachten';
m[x++]='15:Auf Durchgangshöhen und Durchgangsbreiten achten';
m[x++]='90:$<b>Zusätzliche Gefährdungen im Arbeitsumfeld</b>';
m[x++]='91:Prüfen, ob zusätzliche Gefährdungen im Arbeitsumfeld auftreten (z.B. Störungen durch benachbarte Montagestellen).';
m[x++]='92:Bei diesen zusätzlichen Gefährdungen im Arbeitsumfeld sind Schutzmaßnahmen festgelegt.';
