titel[z]='Rigg: Planung';
gefahr[z]='Gefährdungsfaktoren: Unkontrolliert bewegte Teile; Absturz';
fragen[z]='Welche Maßnahmen werden ergriffen, um die Standsicherheit des Riggs zu gewährleisten und eine Überlastung durch Anschlagmittel, Hebezeuge, Lastaufnahmemittel und zusätzliche Lasten im Traversensystem zu vermeiden?';
m[x++]='00:Standsicherheitsnachweis oder Statik beachten';
m[x++]='01:Umwelteinflüsse, vor allem im Außeneinsartz, beachten';
m[x++]='02:Ballastierung und Abspannungen wenn notwendig';
m[x++]='03:Anfahrschutz falls erforderlich vorsehen';
m[x++]='04:Bei Dimensionierung des Riggs Belastung während des Aufbaus berücksichtigen (Hebezeuge, Anschlagmittel)';
m[x++]='05:Dokumentation von Aufbaureihenfolge und Restriktionen anfertigen';
m[x++]='06:Einsatz technischer Arbeitsmittel wie Hubsteiger, Scherenlifte, Scherenbühnen, Material-Lifte zum Einleuchten und zur Rettung vorsehen';
m[x++]='07:Für den Aufbau qualifiziertes Personal vorsehen';
